#ifndef GDN_DECODE_QK8_V16_D128_K_LAST_KERNEL_H
#define GDN_DECODE_QK8_V16_D128_K_LAST_KERNEL_H

#include <cuda.h>
#include <cuda_runtime.h>
#include <torch/extension.h>
#include <c10/cuda/CUDAGuard.h>

#include <stdint.h>
#include <vector>

#ifndef CHECK_CUDA
#define CHECK_CUDA(x) TORCH_CHECK((x).is_cuda(), #x " must be a CUDA tensor")
#endif
#ifndef CHECK_CONTIGUOUS
#define CHECK_CONTIGUOUS(x) TORCH_CHECK((x).is_contiguous(), #x " must be contiguous")
#endif
#ifndef CHECK_DTYPE
#define CHECK_DTYPE(x, dt) TORCH_CHECK((x).dtype() == (dt), #x " has wrong dtype")
#endif

// CUDA launcher (implemented in kernel.cu)
void gdn_decode_qk8_v16_d128_k_last_launch(
    const at::cuda::CUDAStream& stream,
    const at::Half* __restrict__ q_bf16_as_half,   // actually bf16 bits, reinterpreted as Half for raw 16-bit load
    const at::Half* __restrict__ k_bf16_as_half,
    const at::Half* __restrict__ v_bf16_as_half,
    const float* __restrict__ state,               // [B,16,128,128] float32 (k-last layout [V,K])
    const float* __restrict__ A_log,               // [16]
    const at::Half* __restrict__ a_bf16_as_half,   // [B,1,16]
    const float* __restrict__ dt_bias,             // [16]
    const at::Half* __restrict__ b_bf16_as_half,   // [B,1,16]
    float scale,
    int B,
    at::Half* __restrict__ out_bf16_as_half,       // [B,1,16,128] bf16 bits in 16-bit container
    float* __restrict__ new_state                  // [B,16,128,128] float32
);

#endif // GDN_DECODE_QK8_V16_D128_K_LAST_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#include <math_constants.h>

#define CUDA_CHECK(err) do {                           \
  cudaError_t err__ = (err);                           \
  if (err__ != cudaSuccess) {                          \
    printf("CUDA error %s:%d: %s\n",                   \
           __FILE__, __LINE__, cudaGetErrorString(err__)); \
  }                                                    \
} while(0)

static __device__ __forceinline__ float bf16_to_f32_from_u16(uint16_t x) {
  __nv_bfloat16 b;
  *reinterpret_cast<uint16_t*>(&b) = x;
  return __bfloat162float(b);
}
static __device__ __forceinline__ uint16_t f32_to_bf16_u16(float x) {
  __nv_bfloat16 b = __float2bfloat16_rn(x);
  return *reinterpret_cast<uint16_t*>(&b);
}

static __device__ __forceinline__ float sigmoidf_fast(float x) {
  return 1.0f / (1.0f + __expf(-x));
}
static __device__ __forceinline__ float softplusf_fast(float x) {
  // softplus(x) = log1p(exp(x)) with stable branches
  if (x > 20.0f) return x;
  if (x < -20.0f) return __expf(x);
  return log1pf(__expf(x));
}

__constant__ float c_Aexp[16];    // exp(A_log[h])
__constant__ float c_dt_bias[16]; // dt_bias[h]

// Kernel: one CTA per (B, head=0..15, row v=0..127).
// Threads: 128 threads (one per k element) -> compute row update and output dot.
// State layout input/output: [B,H,V,K] (V major, K last).
// Update in "K,V" math: we treat each row v, and compute across K.
__global__ void gdn_decode_kernel(
    const uint16_t* __restrict__ q,   // [B,1,8,128] bf16
    const uint16_t* __restrict__ k,   // [B,1,8,128] bf16
    const uint16_t* __restrict__ v,   // [B,1,16,128] bf16
    const float* __restrict__ state,  // [B,16,128,128] float
    const uint16_t* __restrict__ a,   // [B,1,16] bf16
    const uint16_t* __restrict__ b,   // [B,1,16] bf16
    float scale,
    int B,
    uint16_t* __restrict__ out,       // [B,1,16,128] bf16
    float* __restrict__ new_state     // [B,16,128,128] float
) {
  // grid: x = B, y = head(16), z = v_row(128)
  int batch = (int)blockIdx.x;
  int h = (int)blockIdx.y;     // 0..15
  int vrow = (int)blockIdx.z;  // 0..127
  int tid = (int)threadIdx.x;  // 0..127 (k index)

  if (batch >= B) return;

  // Map v-head to q/k head: repeat_interleave factor=2
  int qk_h = h >> 1; // 0..7

  // Load gates (scalar per (B,h))
  float a_f = bf16_to_f32_from_u16(a[(batch * 16) + h]);
  float b_f = bf16_to_f32_from_u16(b[(batch * 16) + h]);
  float x = a_f + c_dt_bias[h];
  float g = __expf(-c_Aexp[h] * softplusf_fast(x));
  float beta = sigmoidf_fast(b_f);

  // Base pointers
  // q: [B,1,8,128] contiguous => offset = ((batch*1+0)*8+qk_h)*128 + k
  const uint16_t* q_ptr = q + ((batch * 8 + qk_h) * 128);
  const uint16_t* k_ptr = k + ((batch * 8 + qk_h) * 128);
  const uint16_t* v_ptr = v + ((batch * 16 + h) * 128);

  // state: [B,16,128,128] => ((batch*16+h)*128 + vrow)*128 + k
  const float* s_ptr = state + (((batch * 16 + h) * 128 + vrow) * 128);
  float* ns_ptr = new_state + (((batch * 16 + h) * 128 + vrow) * 128);

  // Each thread loads k[tid], q[tid] for later, and state[vrow, tid]
  float k_t = bf16_to_f32_from_u16(k_ptr[tid]);
  float q_t = bf16_to_f32_from_u16(q_ptr[tid]);

  float s_vk = s_ptr[tid];
  float old_s_vk = g * s_vk;

  // Compute old_v[vrow] = sum_k k[k] * old_state[k,vrow]
  // In k-last state representation: state[vrow, k] corresponds to state^T[k,vrow]
  // So dot is sum_k k[k] * old_state[vrow,k].
  float prod = k_t * old_s_vk;

  // Reduce across block (128 threads)
  __shared__ float sh_red[128];
  sh_red[tid] = prod;
  __syncthreads();
  for (int offset = 64; offset > 0; offset >>= 1) {
    if (tid < offset) sh_red[tid] += sh_red[tid + offset];
    __syncthreads();
  }
  float old_v = sh_red[0]; // broadcast by reading sh_red[0] after sync
  __syncthreads();

  // new_v[vrow] = beta*v[vrow] + (1-beta)*old_v
  float v_v = bf16_to_f32_from_u16(v_ptr[vrow]);
  float new_v_val = beta * v_v + (1.0f - beta) * old_v;

  // Update row element:
  // h_state = old_state - k^T@old_v + k^T@new_v
  // For each k index: subtract k[k]*old_v and add k[k]*new_v
  float updated = old_s_vk + k_t * (new_v_val - old_v);
  ns_ptr[tid] = updated;

  // We also need output[vrow] = scale * sum_k q[k] * updated_state[k,vrow]
  // which equals scale * sum_k q[k] * updated_row[vrow,k] in our layout.
  float out_prod = q_t * updated;
  sh_red[tid] = out_prod;
  __syncthreads();
  for (int offset = 64; offset > 0; offset >>= 1) {
    if (tid < offset) sh_red[tid] += sh_red[tid + offset];
    __syncthreads();
  }
  float out_f = scale * sh_red[0];

  // Write output at tid==0 for this (batch,h,vrow)
  if (tid == 0) {
    // out: [B,1,16,128] => ((batch*16+h)*128 + vrow)
    out[(batch * 16 + h) * 128 + vrow] = f32_to_bf16_u16(out_f);
  }
}

void gdn_decode_qk8_v16_d128_k_last_launch(
    const at::cuda::CUDAStream& stream,
    const at::Half* __restrict__ q_bf16_as_half,
    const at::Half* __restrict__ k_bf16_as_half,
    const at::Half* __restrict__ v_bf16_as_half,
    const float* __restrict__ state,
    const float* __restrict__ A_log,
    const at::Half* __restrict__ a_bf16_as_half,
    const float* __restrict__ dt_bias,
    const at::Half* __restrict__ b_bf16_as_half,
    float scale,
    int B,
    at::Half* __restrict__ out_bf16_as_half,
    float* __restrict__ new_state
) {
  // Precompute and upload constants (Aexp, dt_bias). Small (16).
  float h_Aexp[16];
  float h_dt[16];
  CUDA_CHECK(cudaMemcpyAsync(h_dt, dt_bias, 16 * sizeof(float), cudaMemcpyDeviceToHost, stream.stream()));
  CUDA_CHECK(cudaMemcpyAsync(h_Aexp, A_log, 16 * sizeof(float), cudaMemcpyDeviceToHost, stream.stream()));
  CUDA_CHECK(cudaStreamSynchronize(stream.stream()));
  for (int i = 0; i < 16; ++i) h_Aexp[i] = expf(h_Aexp[i]);

  CUDA_CHECK(cudaMemcpyToSymbolAsync(c_Aexp, h_Aexp, 16 * sizeof(float), 0, cudaMemcpyHostToDevice, stream.stream()));
  CUDA_CHECK(cudaMemcpyToSymbolAsync(c_dt_bias, h_dt, 16 * sizeof(float), 0, cudaMemcpyHostToDevice, stream.stream()));

  dim3 block(128, 1, 1);
  dim3 grid((unsigned)B, 16, 128);

  const uint16_t* q_u16 = reinterpret_cast<const uint16_t*>(q_bf16_as_half);
  const uint16_t* k_u16 = reinterpret_cast<const uint16_t*>(k_bf16_as_half);
  const uint16_t* v_u16 = reinterpret_cast<const uint16_t*>(v_bf16_as_half);
  const uint16_t* a_u16 = reinterpret_cast<const uint16_t*>(a_bf16_as_half);
  const uint16_t* b_u16 = reinterpret_cast<const uint16_t*>(b_bf16_as_half);
  uint16_t* out_u16 = reinterpret_cast<uint16_t*>(out_bf16_as_half);

  gdn_decode_kernel<<<grid, block, 0, stream.stream()>>>(
      q_u16, k_u16, v_u16, state, a_u16, b_u16, scale, B, out_u16, new_state
  );
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <c10/cuda/CUDAGuard.h>
#include <ATen/cuda/CUDAContext.h>

#include "kernel.h"

static void check_inputs(
    const torch::Tensor& q,
    const torch::Tensor& k,
    const torch::Tensor& v,
    const torch::Tensor& state,
    const torch::Tensor& A_log,
    const torch::Tensor& a,
    const torch::Tensor& dt_bias,
    const torch::Tensor& b
) {
  CHECK_CUDA(q); CHECK_CUDA(k); CHECK_CUDA(v);
  CHECK_CUDA(state); CHECK_CUDA(A_log); CHECK_CUDA(a); CHECK_CUDA(dt_bias); CHECK_CUDA(b);

  CHECK_CONTIGUOUS(q); CHECK_CONTIGUOUS(k); CHECK_CONTIGUOUS(v);
  CHECK_CONTIGUOUS(state); CHECK_CONTIGUOUS(A_log); CHECK_CONTIGUOUS(a); CHECK_CONTIGUOUS(dt_bias); CHECK_CONTIGUOUS(b);

  TORCH_CHECK(q.dtype() == torch::kBFloat16, "q must be bfloat16");
  TORCH_CHECK(k.dtype() == torch::kBFloat16, "k must be bfloat16");
  TORCH_CHECK(v.dtype() == torch::kBFloat16, "v must be bfloat16");
  TORCH_CHECK(a.dtype() == torch::kBFloat16, "a must be bfloat16");
  TORCH_CHECK(b.dtype() == torch::kBFloat16, "b must be bfloat16");

  TORCH_CHECK(state.dtype() == torch::kFloat32, "state must be float32");
  TORCH_CHECK(A_log.dtype() == torch::kFloat32, "A_log must be float32");
  TORCH_CHECK(dt_bias.dtype() == torch::kFloat32, "dt_bias must be float32");

  TORCH_CHECK(q.dim() == 4, "q must be [B,1,8,128]");
  TORCH_CHECK(k.dim() == 4, "k must be [B,1,8,128]");
  TORCH_CHECK(v.dim() == 4, "v must be [B,1,16,128]");
  TORCH_CHECK(state.dim() == 4, "state must be [B,16,128,128]");
  TORCH_CHECK(a.dim() == 3, "a must be [B,1,16]");
  TORCH_CHECK(b.dim() == 3, "b must be [B,1,16]");
  TORCH_CHECK(A_log.numel() == 16, "A_log must have 16 elements");
  TORCH_CHECK(dt_bias.numel() == 16, "dt_bias must have 16 elements");

  int64_t B = q.size(0);
  TORCH_CHECK(q.size(1) == 1 && q.size(2) == 8 && q.size(3) == 128, "q shape mismatch");
  TORCH_CHECK(k.size(0) == B && k.size(1) == 1 && k.size(2) == 8 && k.size(3) == 128, "k shape mismatch");
  TORCH_CHECK(v.size(0) == B && v.size(1) == 1 && v.size(2) == 16 && v.size(3) == 128, "v shape mismatch");
  TORCH_CHECK(state.size(0) == B && state.size(1) == 16 && state.size(2) == 128 && state.size(3) == 128, "state shape mismatch");
  TORCH_CHECK(a.size(0) == B && a.size(1) == 1 && a.size(2) == 16, "a shape mismatch");
  TORCH_CHECK(b.size(0) == B && b.size(1) == 1 && b.size(2) == 16, "b shape mismatch");
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    c10::optional<double> scale_opt
) {
  check_inputs(q, k, v, state, A_log, a, dt_bias, b);

  const auto B = (int)q.size(0);
  float scale = 0.0f;
  if (scale_opt.has_value() && (float)scale_opt.value() != 0.0f) {
    scale = (float)scale_opt.value();
  } else {
    scale = 1.0f / sqrtf(128.0f);
  }

  // Ensure correct device/stream
  c10::cuda::CUDAGuard device_guard(q.device());
  auto stream = at::cuda::getDefaultCUDAStream(q.device().index());

  // Output allocations
  auto out = torch::empty({B, 1, 16, 128}, torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto new_state = torch::empty_like(state, state.options().dtype(torch::kFloat32));

  // Launch
  gdn_decode_qk8_v16_d128_k_last_launch(
      stream,
      reinterpret_cast<const at::Half*>(q.data_ptr<at::BFloat16>()),
      reinterpret_cast<const at::Half*>(k.data_ptr<at::BFloat16>()),
      reinterpret_cast<const at::Half*>(v.data_ptr<at::BFloat16>()),
      state.data_ptr<float>(),
      A_log.data_ptr<float>(),
      reinterpret_cast<const at::Half*>(a.data_ptr<at::BFloat16>()),
      dt_bias.data_ptr<float>(),
      reinterpret_cast<const at::Half*>(b.data_ptr<at::BFloat16>()),
      scale,
      B,
      reinterpret_cast<at::Half*>(out.data_ptr<at::BFloat16>()),
      new_state.data_ptr<float>());

  // Check errors
  auto err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));
  err = cudaDeviceSynchronize();
  TORCH_CHECK(err == cudaSuccess, "CUDA sync failed: ", cudaGetErrorString(err));

  return {out, new_state};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run,
        py::arg("q"),
        py::arg("k"),
        py::arg("v"),
        py::arg("state"),
        py::arg("A_log"),
        py::arg("a"),
        py::arg("dt_bias"),
        py::arg("b"),
        py::arg("scale") = c10::optional<double>(),
        "gdn_decode_qk8_v16_d128_k_last run (CUDA)");
}
